%[text] # 例4.4（sinc関数のFT）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_04"; % mfilename
%%
syms q Delta
assume(Delta,'real')
assume(Delta,'positive')

h = sinc(q/Delta)/Delta %[output:8da64f18]

H = fourier(h) %[output:387b864a]

H = subs(H,Delta,2) %[output:2dc2ce25]
fplot(H) %[output:2f5d3434]
